def _db_or_skip(work_name: str) -> Path:
    db = DATA / work_name / "tests.sqlite"
    if not db.exists():
        pytest.skip(f"fixture sqlite missing: {db}")
    return db


def _run_cascade(db: Path, scen: str, work: Path,
                 *, csv_disabled: bool = False, csv_dump: bool | None = None):
    """Helper: drive ``run_chain_from_db``.

    ``csv_disabled`` is the legacy parameter name retained for source
    compatibility — when ``True``, csv_dump defaults to False (the new
    default mode); when ``False``, csv_dump defaults to True (legacy
    csv-dump mode).  Callers can override via ``csv_dump=``.
    """
    work.mkdir(parents=True, exist_ok=True)
    if csv_dump is None:
        csv_dump = not csv_disabled
    sols = run_chain_from_db(
        db, scenario_name=scen, work_folder=work, csv_dump=csv_dump,
    )
    # Mirror the ``--csv-dump`` cmd_run_flextool path: snapshot the
    # last sub-solve's Provider so the on-disk surface mirrors what the
    # CLI produces.
    if csv_dump and sols:
        last = next(reversed(list(sols.values())))
        provider = getattr(last, "flex_data_provider", None)
        if provider is not None:
            provider.snapshot_processed_inputs(work)
    return sols


def _final_objective(sols) -> float:
    last = next(reversed(sols.values()))
    # Slim default holds ``obj`` summary; full solution lives on the
    # last step only.  Either field is acceptable.
    if last.obj is not None:
        return float(last.obj)
    return float(last.solution.obj)


def _validate_manifest(work: Path, *, must_have_raw: bool = True) -> dict:
    """Write the manifest and assert its core invariants.

    Returns the parsed manifest dict so callers can inspect specific
    entries.
    """
    path = write_manifest(work)
    assert path == work / "manifest.json"
    assert path.is_file(), f"manifest not written to {path}"
    manifest = json.loads(path.read_text())

    # Schema basics.
    assert manifest["version"] == "1"
    # ISO 8601 parses.
    datetime.fromisoformat(manifest["generated_at"])
    assert manifest["bundle_root"] == str(work.resolve())
    assert isinstance(manifest["files"], list)
    assert len(manifest["files"]) > 0

    # Every entry has the documented keys.
    required = {"key", "category", "path", "exists", "size_bytes",
                "columns", "indices", "note", "producer"}
    for entry in manifest["files"]:
        missing = required - set(entry)
        assert not missing, (
            f"manifest entry missing keys {missing}: {entry}"
        )
        assert entry["category"] in {"raw", "processed"}, (
            f"unknown category on {entry['key']!r}: "
            f"{entry['category']!r}"
        )
        # Each key is in REGISTRY.
        assert entry["key"] in REGISTRY, (
            f"manifest references unknown REGISTRY key: {entry['key']!r}"
        )

    # At least one raw entry should be present in the bundle (the LP
    # cascade always emits >= 1 v_* parquet).
    raw_present = [e for e in manifest["files"]
                   if e["category"] == "raw" and e["exists"]]
    if must_have_raw:
        assert raw_present, (
            "manifest reports no raw files on disk; the cascade should "
            "have emitted at least one v_*.parquet shard.  "
            f"output_raw exists: {(work / 'output_raw').is_dir()}"
        )

    # Every ``exists=True`` entry points at a real file.
    for entry in manifest["files"]:
        if not entry["exists"]:
            continue
        rel = work / entry["path"]
        assert rel.is_file(), (
            f"manifest claims {entry['key']!r} exists at {rel} but the "
            f"file is missing on disk."
        )

    return manifest


def _assert_no_unexpected_solve_data_csvs(work: Path,
                                          whitelist: frozenset[str]) -> None:
    """Solve_data/ may contain only documented out-of-scope basenames.

    Any other ``.csv`` in ``solve_data/`` is a regression — Phase E's
    writer-port gate failed to cover that producer.  Failure prints the
    unexpected set so the next dispatch knows which writer to lift.
    """
    sd = work / "solve_data"
    if not sd.is_dir():
        return  # cleanest possible state — nothing to validate.
    on_disk = {p.name for p in sd.glob("*.csv")}
    unexpected = on_disk - whitelist
    assert not unexpected, (
        f"Phase H default-mode regression: solve_data/ contains "
        f"unexpected CSVs not in the documented out-of-scope "
        f"whitelist.  Unexpected files: {sorted(unexpected)}.  "
        f"Either gate the producing writer (preferred) or add the "
        f"basename to _DOCUMENTED_OUT_OF_SCOPE_SOLVE_DATA with a "
        f"comment explaining why it's out of scope."
    )


def _assert_no_cross_solve_csvs(work: Path) -> None:
    """The cross-solve carriers ride in ``state.cross_solve_carriers``
    (Phase E-d); the on-disk ``cross_solve/`` directory should not be
    created at all under default mode, or if created, it should not
    contain any ``.csv`` files."""
    cs = work / "cross_solve"
    if not cs.is_dir():
        return
    csvs = sorted(p.name for p in cs.glob("*.csv"))
    assert not csvs, (
        f"Phase H default-mode regression: cross_solve/ contains CSVs "
        f"under the in-memory cascade — Phase E-d migrated the cross-"
        f"solve carriers to in-memory state.cross_solve_carriers.  "
        f"Unexpected files: {csvs}"
    )


def _output_raw_parquets(work: Path) -> list[Path]:
    raw = work / "output_raw"
    if not raw.is_dir():
        return []
    return sorted(raw.glob("v_*.parquet"))


# ---------------------------------------------------------------------------
# Default-mode invariants (in-memory cascade).
# ---------------------------------------------------------------------------


def test_default_mode_work_base_clean_bundle(tmp_path: Path) -> None:
    """Default mode on ``work_base`` produces a clean output bundle:

    * No unexpected CSVs in ``solve_data/`` / ``cross_solve/`` (Phase
      E gate honoured; the documented out-of-scope set is allowed).
    * ``output_raw/v_*.parquet`` exists.
    * ``manifest.json`` schema correct; raw entries map to real files.
    """
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])
    work = tmp_path / "default_mode"
    sols = _run_cascade(db, _FIX_SINGLE_ROLL[1], work, csv_disabled=True)
    assert sols, "default-mode cascade returned no sub-solves"

    # Raw parquet trail must be present.
    parquets = _output_raw_parquets(work)
    assert parquets, (
        f"default mode: no v_*.parquet under {work / 'output_raw'} — "
        f"the cascade's raw-result writer should always emit at least "
        f"one shard."
    )

    # Cascade-internal CSV gate honoured.
    _assert_no_unexpected_solve_data_csvs(
        work, _DOCUMENTED_OUT_OF_SCOPE_SOLVE_DATA,
    )
    _assert_no_cross_solve_csvs(work)

    # Manifest writes successfully and validates.
    _validate_manifest(work, must_have_raw=True)


def test_default_mode_captures_objective(tmp_path: Path) -> None:
    """Capture the default-mode objective on ``work_base``.  This pins
    the value used by the csv-dump-parity test below."""
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])
    work = tmp_path / "default_mode"
    sols = _run_cascade(db, _FIX_SINGLE_ROLL[1], work, csv_disabled=True)
    obj = _final_objective(sols)
    assert math.isfinite(obj), f"objective not finite: {obj}"
    # Sanity: work_base's golden objective is ~4.78e9.  Loose bound.
    assert 1e6 < obj < 1e12, f"work_base objective out of expected band: {obj}"


