def test_csv_dump_mode_work_base_emits_legacy_csvs(tmp_path: Path) -> None:
    """With CSV emission ON, ``solve_data/`` should carry the legacy
    CSV set (sample a few key basenames).  Output_raw parquets still
    emit; manifest still writes."""
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])
    work = tmp_path / "csv_dump"
    sols = _run_cascade(db, _FIX_SINGLE_ROLL[1], work, csv_disabled=False)
    assert sols

    sd = work / "solve_data"
    assert sd.is_dir()
    on_disk = {p.name for p in sd.glob("*.csv")}
    # Sample a few high-traffic basenames the gate-on path emits.
    for sample in (
        "p_entity_unitsize.csv",
        "steps_in_use.csv",
        "p_inflation_factor_operations_yearly.csv",
    ):
        assert sample in on_disk, (
            f"csv-dump mode: expected {sample!r} on disk under "
            f"{sd}, but it's missing.  Was the writer-port emission "
            f"gate accidentally left on?  on-disk basenames: "
            f"{sorted(on_disk)[:20]}..."
        )

    # Raw parquets + manifest stay correct.
    assert _output_raw_parquets(work)
    _validate_manifest(work, must_have_raw=True)


def test_objective_parity_default_vs_csv_dump(tmp_path: Path) -> None:
    """The default (gate-on) and csv-dump (gate-off) cascade must
    produce the same final objective — this is the Phase E-e parity
    gate, asserted directly at the cascade-end on ``work_base``."""
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])

    work_default = tmp_path / "default"
    sols_default = _run_cascade(
        db, _FIX_SINGLE_ROLL[1], work_default, csv_disabled=True,
    )
    obj_default = _final_objective(sols_default)

    work_dump = tmp_path / "dump"
    sols_dump = _run_cascade(
        db, _FIX_SINGLE_ROLL[1], work_dump, csv_disabled=False,
    )
    obj_dump = _final_objective(sols_dump)

    assert math.isclose(obj_default, obj_dump, rel_tol=1e-6), (
        f"default-mode objective {obj_default} does not match csv-dump "
        f"mode {obj_dump} within rel_tol=1e-6.  Phase E-e parity gate "
        f"broken."
    )


def test_csv_dump_mode_multi_roll_cascade(tmp_path: Path) -> None:
    """Multi-roll cascade under csv-dump mode (CSV emission ON).
    Asserts: cascade completes with > 1 sub-solve, raw parquets per
    sub-solve are emitted, manifest writes.

    The csv-emission-disabled mode for multi-roll is currently
    blocked by the loader-side ``input.py::_read_p_flow_max`` /
    ``_read_unitsize`` family (not seed-aware).  Verifying the
    csv-dump-mode multi-roll path proves the cascade itself still
    works correctly; the in-memory seed extension to the loader-side
    reads is a follow-up dispatch.
    """
    db = _db_or_skip(_FIX_MULTI_ROLL[0])
    work = tmp_path / "csv_dump_multi"
    sols = _run_cascade(db, _FIX_MULTI_ROLL[1], work, csv_disabled=False)
    assert len(sols) >= 2, (
        f"expected multi-roll fixture to produce >= 2 sub-solves; got "
        f"{len(sols)}: {list(sols)}"
    )
    # Each sub-solve emits its own parquet shards (the cascade's raw
    # writer keys files by ``v_<name>__<solve>.parquet``).  Expect at
    # least one shard per sub-solve for ``v_flow``.
    raw = work / "output_raw"
    flows = sorted(raw.glob("v_flow__*.parquet"))
    assert len(flows) == len(sols), (
        f"expected {len(sols)} v_flow shards (one per sub-solve); got "
        f"{len(flows)}: {[p.name for p in flows]}"
    )
    _validate_manifest(work, must_have_raw=True)


