# ---------------------------------------------------------------------------
# External-consumer smoke test (the "fresh eye" gate from the handoff).
# ---------------------------------------------------------------------------


def test_external_consumer_can_load_bundle(tmp_path: Path) -> None:
    """An external consumer opens ``manifest.json``, walks the bundle,
    and computes a tiny summary stat from each present file.  This
    asserts the bundle is self-describing — i.e. a tool can be written
    without knowing FlexTool internals."""
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])
    work = tmp_path / "bundle"
    _run_cascade(db, _FIX_SINGLE_ROLL[1], work, csv_disabled=True)
    _validate_manifest(work, must_have_raw=True)

    manifest_path = work / "manifest.json"
    manifest = json.loads(manifest_path.read_text())

    # Simulate an external tool:
    #   1. Open manifest.json
    #   2. For each present file, load it (parquet via polars, CSV via
    #      polars) and compute a one-stat summary.
    #   3. Assert non-zero stats accumulated (some files are non-empty).
    n_files_inspected = 0
    n_rows_total = 0
    bundle_root = Path(manifest["bundle_root"])
    for entry in manifest["files"]:
        if not entry["exists"]:
            continue
        path = bundle_root / entry["path"]
        assert path.is_file(), (
            f"manifest claims {entry['key']!r} exists but {path} not on "
            f"disk."
        )
        try:
            if path.suffix == ".parquet":
                df = pl.scan_parquet(path).collect()
            elif path.suffix == ".csv":
                df = pl.read_csv(path)
            else:
                # Unknown extension — manifest schema is forward
                # compatible but the smoke test only knows about
                # parquet + CSV.  Skip.
                continue
        except Exception as exc:  # noqa: BLE001
            pytest.fail(
                f"external consumer failed to load {entry['key']!r} at "
                f"{path}: {exc}"
            )
        n_files_inspected += 1
        n_rows_total += df.height

    assert n_files_inspected > 0, (
        "external consumer inspected zero files — manifest claims "
        f"{sum(1 for f in manifest['files'] if f['exists'])} present "
        "files but none could be loaded.  Bundle self-description "
        "broken."
    )
    assert n_rows_total > 0, (
        "external consumer found zero rows across all present files; "
        "the bundle's data shrank to nothing — likely a cascade-side "
        "regression that pruned the raw parquet emit step."
    )


# ---------------------------------------------------------------------------
# Manifest persistence — running the cascade twice (with different work
# folders) does not leak state between bundles.
# ---------------------------------------------------------------------------


def test_two_independent_runs_produce_independent_manifests(
    tmp_path: Path,
) -> None:
    """Two cascade runs into separate work folders produce two
    independent manifests.  Catches any accidental shared mutable
    state in the bundle/registry plumbing."""
    db = _db_or_skip(_FIX_SINGLE_ROLL[0])

    work_a = tmp_path / "run_a"
    work_b = tmp_path / "run_b"
    sols_a = _run_cascade(db, _FIX_SINGLE_ROLL[1], work_a, csv_disabled=True)
    sols_b = _run_cascade(db, _FIX_SINGLE_ROLL[1], work_b, csv_disabled=True)
    assert sols_a and sols_b

    m_a = _validate_manifest(work_a, must_have_raw=True)
    m_b = _validate_manifest(work_b, must_have_raw=True)

    assert m_a["bundle_root"] != m_b["bundle_root"], (
        "two cascade runs produced the same bundle_root in their "
        f"manifests — accidental shared state?  Both report "
        f"{m_a['bundle_root']!r}"
    )

    # Each manifest's files[].path is bundle-root-relative; the same
    # registry keys appear in both manifests (REGISTRY is global), but
    # the resolved absolute paths must differ.
    paths_a = {entry["path"] for entry in m_a["files"] if entry["exists"]}
    paths_b = {entry["path"] for entry in m_b["files"] if entry["exists"]}
    assert paths_a, "manifest a has no present files"
    assert paths_b, "manifest b has no present files"
